  ('islands-e3452428-moex-00120', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於教師申訴與訴願程序之敘述，下列何者錯誤？ 提起申訴後，得復依訴願法提起訴願 申訴程序終結前提起訴願，應將該事件移轉於受理教師申訴機關 教師申訴得分為申訴、再申訴二級程序 原措施屬行政處分者，再申訴決定視同訴願決定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
