  ('islands-e3452428-moex-00122', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '甲提起訴願卻漏未於訴願書上簽名或蓋章，受理訴願機關通知甲應於20天內補正。惟經過30天後 甲仍未補正。下列敘述何者正確？ 受理訴願機關應再次通知甲補正 受理訴願機關應為不受理之決定 受理訴願機關仍應就訴願書所載內容為實體審議 受理訴願機關應逕行駁回其訴願 3601', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00123', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政訴訟之保全程序，下列敘述何者正確？ 假扣押之聲請，應由請求標的所在地之地方行政法院管轄 公法上之權利因現狀變更，有不能實現或甚難實現之虞者，為保全強制執行，得聲請假扣押 假扣押裁定後，尚未提起給付之訴者，應於裁定送達後20日內提起 假處分之聲請，由管轄本案之行政法院管轄。但有急迫情形時，得由請求標的所在地之地方行政法 院管轄', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
